"""
title: Get Full Sources
author: Eli Pinals (and gpt ofc)
icon_url: https://www.svgrepo.com/download/521518/book-open.svg
"""

from pydantic import BaseModel
from typing import Optional
import asyncio
import requests
import re


class Action:
    class Valves(BaseModel):
        pass

    def __init__(self):
        self.valves = self.Valves()

    def generate_request_id(self, question):
        # Convert to lowercase
        request_id = question.lower()
        # Remove all non-alphanumeric characters except spaces
        request_id = re.sub(r"[^a-z0-9\s]", "", request_id)
        # Replace multiple spaces with a single underscore
        request_id = re.sub(r"\s+", "_", request_id.strip())
        # Truncate to 100 characters
        request_id = request_id[:100]

        return request_id

    async def action(
        self,
        body: dict,
        __user__=None,
        __event_emitter__=None,
        __event_call__=None,
    ) -> Optional[dict]:
        messages = body.get("messages", [])
        user_messages = [msg["content"] for msg in messages if msg["role"] == "user"]
        latest_user_message = user_messages[-1] if user_messages else None

        if not latest_user_message:
            if __event_emitter__:
                await __event_emitter__(
                    {
                        "type": "message",
                        "data": {"content": "Error: No user message found."},
                    }
                )
            return

        request_id = self.generate_request_id(latest_user_message)

        try:
            response = requests.post(
                "https://llm-clean-git-eli-llm.apps.tenoran.automation.otic.open6g.net/get_full_sources",  # key route
                json={"request_id": request_id},
            )
            response_data = response.json()

            if response_data.get("status") == "success":
                sources = response_data.get("sources", [])
                formatted_sources = "\n\n### Sources\n"
                for src in sources:
                    # formatted_sources += f"- [{src['document_title']}: *{src['section_title']}*]({src['link']})\n"     # doc title: section title
                    formatted_sources += f"- [\"{src['section_title']}\" — *{src['document_title']}*]({src['link']})\n"  # section title - doc title
                    # full markdown chunk
                    # formatted_sources += (f"  - Section Contents:\n  - {src['chunk_content']}\n")
            else:
                formatted_sources = "\n\n**No sources found!**"

        except requests.exceptions.JSONDecodeError:
            formatted_sources = "\n\n**Error:** Invalid JSON response."
        except Exception as e:
            formatted_sources = f"\n\n**Error fetching sources:** {str(e)}"

        if __event_emitter__:
            await __event_emitter__(
                {
                    "type": "status",
                    "data": {"description": "Getting Sources...", "done": False},
                }
            )
            await asyncio.sleep(1)
            await __event_emitter__(
                {
                    "type": "message",
                    "data": {
                        "content": formatted_sources,
                        "id": f"sources.{request_id}",
                        "name": "Get Sources",
                    },
                }
            )
            await __event_emitter__(
                {"type": "status", "data": {"description": "", "done": True}}
            )
